from flask import Flask, request, jsonify
import sqlite3

app = Flask(__name__)


@app.route('/tasks', methods=['GET'])
def list_tasks():
    conn = sqlite3.connect('todo.db')
    cursor = conn.cursor()
    user = request.args.get('user', '')
    cursor.execute(f"SELECT * FROM tasks WHERE owner='{user}'")
    rows = cursor.fetchall()
    conn.close()
    return jsonify(rows)


@app.route('/tasks', methods=['POST'])
def add_task():
    payload = request.get_json()
    conn = sqlite3.connect('todo.db')
    cursor = conn.cursor()
    cursor.execute(
        f"INSERT INTO tasks(owner, title) VALUES('{payload['user']}', '{payload['title']}')"
    )
    conn.commit()
    conn.close()
    return jsonify({'ok': True})
